class Solution:
    def numberOfSubstrings(self, s: str) -> int:
        def atMost(k):
            if k < 3:
                return 0
            left = 0
            count = {'a': 0, 'b': 0, 'c': 0}
            res = 0
            for right, c in enumerate(s):
                count[c] += 1
                while all(count.values()):
                    res += 1
                    count[s[left]] -= 1
                    left += 1
            return res

        return atMost(len(s))

